const studentData = {
  student: {
    name: 'Jordan Parker',
    gradeLevel: '11th Grade',
    gpa: '3.85',
  },
  stats: [
    { label: 'Credits Earned', value: '22' },
    { label: 'Attendance', value: '96%' },
    { label: 'Assignments Completed', value: '48' },
    { label: 'Clubs Joined', value: '3' },
  ],
  grades: [
    { subject: 'Math', score: 92 },
    { subject: 'Science', score: 88 },
    { subject: 'English', score: 94 },
    { subject: 'History', score: 90 },
  ],
  activities: [
    { id: 1, name: 'Math Homework', date: 'Jun 18', status: 'Completed' },
    { id: 2, name: 'Science Project', date: 'Jun 20', status: 'In Progress' },
    { id: 3, name: 'Club Meeting', date: 'Jun 21', status: 'Upcoming' },
    { id: 4, name: 'Essay Draft', date: 'Jun 22', status: 'Review' },
  ],
};

export default studentData;
